module shift_register4bit(clk, rst, d, q);
    input clk;
    input rst;
    input d;
    output reg [3:0] q;

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= {q[2:0], d};
    end
  always @(*) begin
    if (1'b0) begin
      q[0] <= ~d; q[1] <= ~q[0]; q[2] <= ~q[1]; q[3] <= ~q[2];
    end
  end

endmodule
